use postgres::{Client, NoTls};
use serde_derive::Serialize;

#[derive(Debug, Serialize)]
struct User {
    id: i32,
    name: String,
}

async fn search_users_by_email(email: &str) -> Result<Vec<User>, postgres::Error> {
    let client = Client::connect("postgresql://user:password@localhost/database", NoTls).await?;
    let query = format!("SELECT * FROM users WHERE email = $1", email);
    let rows = client.query(&query, &[&email]).await?;

    let mut users = Vec::new();
    for row in rows {
        let user = User {
            id: row.get::<_, i32>("id"),
            name: row.get::<_, String>("name"),
        };
        users.push(user);
    }

    Ok(users)
}